insert into public.messages (id, conversation_id, sender_type, sender_name, text, status, created_at) values
  ('00000000-0000-0000-0000-000000000401', '00000000-0000-0000-0000-000000000301', 'client', 'Иванов И.И.', 'Здравствуйте! Я хотел бы узнать подробнее о процедуре банкротства.', 'read', '2026-03-16T09:00:00Z'),
  ('00000000-0000-0000-0000-000000000402', '00000000-0000-0000-0000-000000000301', 'agent', 'Алексей Петров', 'Добрый день! Конечно, расскажу. Для начала мне нужно уточнить сумму вашей задолженности и количество кредиторов.', 'read', '2026-03-16T09:05:00Z'),
  ('00000000-0000-0000-0000-000000000403', '00000000-0000-0000-0000-000000000301', 'client', 'Иванов И.И.', 'У меня 3 кредита на общую сумму около 2.5 миллионов рублей. Два в банках и один микрозайм.', 'read', '2026-03-16T09:15:00Z'),
  ('00000000-0000-0000-0000-000000000404', '00000000-0000-0000-0000-000000000301', 'agent', 'Алексей Петров', 'Понял вас. При такой сумме задолженности вы подходите под процедуру банкротства. Давайте назначим встречу для детального обсуждения?', 'read', '2026-03-16T09:20:00Z'),
  ('00000000-0000-0000-0000-000000000405', '00000000-0000-0000-0000-000000000301', 'client', 'Иванов И.И.', 'Да, давайте. Когда можно подъехать?', 'read', '2026-03-16T10:00:00Z'),
  ('00000000-0000-0000-0000-000000000406', '00000000-0000-0000-0000-000000000301', 'system', 'Система', 'Менеджер Елена Волкова подключилась к диалогу', 'read', '2026-03-16T10:10:00Z'),
  ('00000000-0000-0000-0000-000000000407', '00000000-0000-0000-0000-000000000301', 'manager', 'Елена Волкова', 'Добрый день! Я координирую работу с вашим делом. Можем записать вас на завтра на 14:00.', 'delivered', '2026-03-16T10:15:00Z'),
  ('00000000-0000-0000-0000-000000000408', '00000000-0000-0000-0000-000000000301', 'client', 'Иванов И.И.', 'Здравствуйте, хотел уточнить по документам...', 'sent', '2026-03-16T10:30:00Z');
